def _micro_strategy_metric_to_nested(
    micro_strategy_metric: MicroStrategyMetric,
) -> MicroStrategyMetricNested:
    """Convert flat MicroStrategyMetric to nested format."""
    attrs = MicroStrategyMetricAttributes()
    _populate_micro_strategy_metric_attrs(attrs, micro_strategy_metric)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        micro_strategy_metric,
        _MICRO_STRATEGY_METRIC_REL_FIELDS,
        MicroStrategyMetricRelationshipAttributes,
    )
    return MicroStrategyMetricNested(
        guid=micro_strategy_metric.guid,
        type_name=micro_strategy_metric.type_name,
        status=micro_strategy_metric.status,
        version=micro_strategy_metric.version,
        create_time=micro_strategy_metric.create_time,
        update_time=micro_strategy_metric.update_time,
        created_by=micro_strategy_metric.created_by,
        updated_by=micro_strategy_metric.updated_by,
        classifications=micro_strategy_metric.classifications,
        classification_names=micro_strategy_metric.classification_names,
        meanings=micro_strategy_metric.meanings,
        labels=micro_strategy_metric.labels,
        business_attributes=micro_strategy_metric.business_attributes,
        custom_attributes=micro_strategy_metric.custom_attributes,
        pending_tasks=micro_strategy_metric.pending_tasks,
        proxy=micro_strategy_metric.proxy,
        is_incomplete=micro_strategy_metric.is_incomplete,
        provenance_type=micro_strategy_metric.provenance_type,
        home_id=micro_strategy_metric.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _micro_strategy_metric_from_nested(
    nested: MicroStrategyMetricNested,
) -> MicroStrategyMetric:
    """Convert nested format to flat MicroStrategyMetric."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else MicroStrategyMetricAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _MICRO_STRATEGY_METRIC_REL_FIELDS,
        MicroStrategyMetricRelationshipAttributes,
    )
    return MicroStrategyMetric(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_micro_strategy_metric_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _micro_strategy_metric_to_nested_bytes(
    micro_strategy_metric: MicroStrategyMetric, serde: Serde
) -> bytes:
    """Convert flat MicroStrategyMetric to nested JSON bytes."""
    return serde.encode(_micro_strategy_metric_to_nested(micro_strategy_metric))


def _micro_strategy_metric_from_nested_bytes(
    data: bytes, serde: Serde
) -> MicroStrategyMetric:
    """Convert nested JSON bytes to flat MicroStrategyMetric."""
    nested = serde.decode(data, MicroStrategyMetricNested)
    return _micro_strategy_metric_from_nested(nested)


